use serde::{Deserialize, Serialize};

use crate::gg_compiler::{GgEdgeType, GgNode, GgTopology};
use crate::source_map::SourceSpan;

/// Polyglot-specific diagnostic codes detected via topological analysis.
#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
pub enum PolyglotDiagnosticCode {
    /// Resource acquired (FORK) without matching release (FOLD).
    ResourceLeak,
    /// Concurrent spawn without synchronization join.
    SpawnWithoutJoin,
    /// Error path swallowed -- catch/rescue/except with no action.
    ErrorSwallowed,
    /// Try without catch -- error paths not handled.
    MissingErrorHandler,
    /// Unbounded loop without termination proof.
    UnboundedLoop,
    /// Concurrent FORKs without synchronization FOLD.
    RaceNoSync,
    /// Cyclic SLIVER edges indicating potential deadlock.
    DeadlockCycle,
    /// Disconnected graph components (unreachable code).
    UnreachableComponent,
    /// Assignment node with no outgoing PROCESS (dead store).
    DeadStore,

    // ── Untangling: flow improvement opportunities ────────────────────
    // Not bugs -- topologically equivalent but faster forms exist.
    // Like treeshaking eliminates dead branches, untangling eliminates
    // dead algorithmic paths: O(N²) that should be O(N log N), spread
    // that should be single-pass, sequential that should be parallel.
    // Each untangling has a corresponding Lean proof of equivalence
    // (RotationPatterns.lean).
    /// Spread deopt: Math.max/min(...array) in loop. Untangle → single-pass.
    /// Lean: THM-FREQ-EQUIVALENCE (table lookup = inline computation).
    UntangleSpread,
    /// Quadratic nested loop over same collection. Untangle → sort-based.
    /// Lean: THM-GINI-SORT-EQUIVALENCE (O(N²) = O(N log N) result).
    UntangleQuadratic,
    /// queue.shift() in BFS loop. Untangle → index pointer.
    /// Lean: THM-QUEUE-SHIFT-EQUIVALENCE (same traversal order).
    UntangleShift,
    /// Division by constant inside inner loop. Untangle → deferred division.
    /// Lean: THM-DEFER-DIVISION-EQUIVALENCE (distributivity).
    UntangleDefer,
    /// .filter() by category called repeatedly. Untangle → type index.
    /// Lean: THM-TYPEINDEX-INVARIANT (incremental index = filter).
    UntangleTypeIndex,
    /// Per-element division in normalization. Untangle → reciprocal multiply.
    /// Lean: THM-RECIPROCAL-MULTIPLY-EQUIV (a*(1/x) = a/x).
    UntangleReciprocal,

    // ── Knot Classification: structural topology patterns ─────────────
    // These detect the knot TYPE of the topology, not just local tangles.
    // They require global graph analysis (not just per-node inspection).
    /// Hopf link: two components coupled through shared mutable state.
    /// Neither is tangled alone but they cross each other.
    /// Untangle: replace shared state with message passing.
    HopfLink,
    /// Borromean rings: N components where no (N-1) subset is coupled,
    /// but all N are collectively entangled through a shared dependency.
    /// Invisible to pairwise inspection. Requires full-graph analysis.
    /// Generalized: Brunnian link of arity N.
    BrunnianLink,
    /// Trefoil: triple nested iteration over the same collection.
    /// Three crossings. Unknotting number 1 via sort-based reduction.
    TrefoilKnot,
    /// Amphichiral: two code paths that mirror each other (build/query,
    /// serialize/deserialize, encode/decode). Untangling one automatically
    /// untangles the other by mirror symmetry.
    AmphichiralKnot,
}

impl PolyglotDiagnosticCode {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::ResourceLeak => "RESOURCE_LEAK",
            Self::SpawnWithoutJoin => "SPAWN_WITHOUT_JOIN",
            Self::ErrorSwallowed => "ERROR_SWALLOWED",
            Self::MissingErrorHandler => "MISSING_ERROR_HANDLER",
            Self::UnboundedLoop => "UNBOUNDED_LOOP",
            Self::RaceNoSync => "RACE_NO_SYNC",
            Self::DeadlockCycle => "DEADLOCK_CYCLE",
            Self::UnreachableComponent => "UNREACHABLE_COMPONENT",
            Self::DeadStore => "DEAD_STORE",
            Self::UntangleSpread => "UNTANGLE_SPREAD",
            Self::UntangleQuadratic => "UNTANGLE_QUADRATIC",
            Self::UntangleShift => "UNTANGLE_SHIFT",
            Self::UntangleDefer => "UNTANGLE_DEFER",
            Self::UntangleTypeIndex => "UNTANGLE_TYPE_INDEX",
            Self::UntangleReciprocal => "UNTANGLE_RECIPROCAL",
            Self::HopfLink => "HOPF_LINK",
            Self::BrunnianLink => "BRUNNIAN_LINK",
            Self::TrefoilKnot => "TREFOIL_KNOT",
            Self::AmphichiralKnot => "AMPHICHIRAL_KNOT",
        }
    }

    pub fn severity(&self) -> DiagnosticSeverity {
        match self {
            Self::ResourceLeak => DiagnosticSeverity::Error,
            Self::SpawnWithoutJoin => DiagnosticSeverity::Warning,
            Self::ErrorSwallowed => DiagnosticSeverity::Warning,
            Self::MissingErrorHandler => DiagnosticSeverity::Warning,
            Self::UnboundedLoop => DiagnosticSeverity::Info,
            Self::RaceNoSync => DiagnosticSeverity::Error,
            Self::DeadlockCycle => DiagnosticSeverity::Error,
            Self::UnreachableComponent => DiagnosticSeverity::Warning,
            Self::DeadStore => DiagnosticSeverity::Info,
            // Untangling: hints, not errors -- equivalent topology exists
            Self::UntangleSpread => DiagnosticSeverity::Hint,
            Self::UntangleQuadratic => DiagnosticSeverity::Hint,
            Self::UntangleShift => DiagnosticSeverity::Hint,
            Self::UntangleDefer => DiagnosticSeverity::Hint,
            Self::UntangleTypeIndex => DiagnosticSeverity::Hint,
            Self::UntangleReciprocal => DiagnosticSeverity::Hint,
            Self::HopfLink => DiagnosticSeverity::Warning,
            Self::BrunnianLink => DiagnosticSeverity::Warning,
            Self::TrefoilKnot => DiagnosticSeverity::Hint,
            Self::AmphichiralKnot => DiagnosticSeverity::Hint,
        }
    }

    pub fn description(&self) -> &'static str {
        match self {
            Self::ResourceLeak => "Resource acquired but never released. FORK (acquire) without matching FOLD (release) creates a topological deficit.",
            Self::SpawnWithoutJoin => "Concurrent task spawned but never joined. The spawned FORK has no synchronizing FOLD.",
            Self::ErrorSwallowed => "Error path enters a FOLD that destroys all information. The catch/rescue handler discards the error.",
            Self::MissingErrorHandler => "Try block without catch handler. Error FORK has no matching error FOLD.",
            Self::UnboundedLoop => "Loop with unbounded beta-1. No termination proof found in the topology cycle.",
            Self::RaceNoSync => "Concurrent FORKs detected without a synchronizing FOLD. Potential race condition.",
            Self::DeadlockCycle => "Cyclic SLIVER edges detected. Lock ordering creates potential deadlock.",
            Self::UnreachableComponent => "Disconnected topology component detected. Code after this point is unreachable.",
            Self::DeadStore => "Value assigned but never read. Assignment node has no outgoing PROCESS.",
            Self::UntangleSpread => "Spread operator on array in loop (e.g. Math.max(...arr)). Untangle: single-pass min/max eliminates V8 deopt and allocation. [THM-FREQ-EQUIVALENCE]",
            Self::UntangleQuadratic => "Nested loop over same collection suggests O(N²) where O(N log N) or O(N) exists. Untangle: sort-based or hash-based reduction. [THM-GINI-SORT-EQUIVALENCE]",
            Self::UntangleShift => "Array.shift() in loop body creates O(N) dequeue (copies all remaining elements). Untangle: index pointer gives O(1) dequeue. [THM-QUEUE-SHIFT-EQUIVALENCE]",
            Self::UntangleDefer => "Division by loop-invariant value inside inner loop. Untangle: accumulate then divide once at end. [THM-DEFER-DIVISION-EQUIVALENCE]",
            Self::UntangleTypeIndex => "Collection filtered by category multiple times. Untangle: maintain incremental type index on insert, query in O(1). [THM-TYPEINDEX-INVARIANT]",
            Self::UntangleReciprocal => "Per-element division in normalization loop. Untangle: compute reciprocal once, multiply N times. [THM-RECIPROCAL-MULTIPLY-EQUIV]",
            Self::HopfLink => "Hopf link: two components coupled through shared mutable state. Neither is tangled alone but they cross at the shared resource. Untangle: replace shared state with message passing to unlink the rings.",
            Self::BrunnianLink => "Brunnian link: N components where no (N-1) subset is coupled, but all N are collectively entangled through a shared dependency. INVISIBLE to pairwise code review. Untangle: make the shared dependency explicit via per-pair contracts.",
            Self::TrefoilKnot => "Trefoil knot: triple nested iteration over the same collection (3 crossings). Untangle: sort + single linear pass. [THM-GINI-SORT-EQUIVALENCE]",
            Self::AmphichiralKnot => "Amphichiral knot: two code paths that mirror each other (e.g. serialize/deserialize, build/query). Untangling one automatically untangles the mirror. Fix the canonical direction; the inverse follows.",
        }
    }
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
pub enum DiagnosticSeverity {
    Error,
    Warning,
    Info,
    /// Untangling opportunity: equivalent faster topology exists.
    /// Not a bug -- the code is correct but a proven-equivalent
    /// restructuring would improve flow.
    Hint,
}

impl DiagnosticSeverity {
    pub fn as_sarif(&self) -> &'static str {
        match self {
            Self::Error => "error",
            Self::Warning => "warning",
            Self::Info => "note",
            Self::Hint => "note", // SARIF has no "hint" level; map to note with tag
        }
    }
}

/// Static accounting surface for forked obligations inside one extracted topology.
/// Ghost mass is the unresolved portion of resource/spawn obligations after
/// fold (release/join) accounting. Leak-witness vents remain ghost mass:
/// they prove failed accounting rather than discharging it.
#[derive(Clone, Debug, Default, Serialize, Deserialize, PartialEq, Eq)]
pub struct GhostMassLedger {
    pub forked_mass: usize,
    pub live_mass: usize,
    pub folded_mass: usize,
    pub vented_mass: usize,
    pub accounted_mass: usize,
    pub ghost_mass: usize,
    pub leak_debt: usize,
}

/// A diagnostic finding from polyglot analysis.
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct PolyglotDiagnostic {
    pub code: PolyglotDiagnosticCode,
    pub message: String,
    pub severity: DiagnosticSeverity,
    /// Source location (if available via source map).
    pub location: Option<SourceSpan>,
    /// Related GG node IDs.
    pub related_nodes: Vec<String>,
    /// Lean theorem or ledger anchor backing this diagnostic.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub theorem_anchor: Option<String>,
    /// File/function ghost mass at the time this diagnostic was emitted.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub ghost_mass: Option<usize>,
}

/// Analyze a GG topology for universal bug patterns and untangling opportunities.
pub fn analyze_topology(topology: &GgTopology) -> Vec<PolyglotDiagnostic> {
    let mut diagnostics = Vec::new();

    // Bug detection
    detect_resource_leaks(topology, &mut diagnostics);
    detect_spawn_leaks(topology, &mut diagnostics);
    detect_missing_error_handlers(topology, &mut diagnostics);
    detect_unbounded_loops(topology, &mut diagnostics);
    detect_unreachable_components(topology, &mut diagnostics);

    // Untangling: flow improvement opportunities
    detect_untangling_opportunities(topology, &mut diagnostics);

    // Knot classification: global topology patterns
    detect_knot_patterns(topology, &mut diagnostics);

    let ghost_mass_ledger = compute_ghost_mass_ledger(topology);
    attach_theorem_surface(&mut diagnostics, &ghost_mass_ledger);

    diagnostics
}

pub fn compute_ghost_mass_ledger(topology: &GgTopology) -> GhostMassLedger {
    let count_with_label = |label: &str| {
        topology
            .nodes
            .iter()
            .filter(|node| node.labels.iter().any(|node_label| node_label == label))
            .count()
    };

    // GG topology accounting operates on emitted GG labels, not upstream CFG kinds.
    let resource_acquires = count_with_label("Acquire");
    let concurrent_spawns = count_with_label("Spawn");
    let resource_releases = count_with_label("Release");
    let sync_joins = count_with_label("Join");
    let leak_vents = topology
        .nodes
        .iter()
        .filter(|node| {
            node.labels.contains(&"ResourceLeak".to_string())
                || node.labels.contains(&"SpawnLeak".to_string())
        })
        .count();

    let forked_mass = resource_acquires + concurrent_spawns;
    let folded_mass = resource_releases + sync_joins;
    let vented_mass = leak_vents;
    let accounted_mass = folded_mass;
    let ghost_mass = forked_mass.saturating_sub(accounted_mass);

    GhostMassLedger {
        forked_mass,
        live_mass: ghost_mass,
        folded_mass,
        vented_mass,
        accounted_mass,
        ghost_mass,
        leak_debt: ghost_mass,
    }
}

fn attach_theorem_surface(
    diagnostics: &mut [PolyglotDiagnostic],
    ghost_mass_ledger: &GhostMassLedger,
) {
    for diagnostic in diagnostics {
        let theorem_anchor = match diagnostic.code {
            PolyglotDiagnosticCode::ResourceLeak => Some("resource_leak_is_cavitation"),
            PolyglotDiagnosticCode::SpawnWithoutJoin => Some("memory_leak_master"),
            _ => None,
        };

        diagnostic.theorem_anchor = theorem_anchor.map(str::to_string);
        if diagnostic.theorem_anchor.is_some() {
            diagnostic.ghost_mass = Some(ghost_mass_ledger.ghost_mass);
        }
    }
}

// ═══════════════════════════════════════════════════════════════════════
// Untangling: static analysis for flow improvement opportunities
//
// Treeshaking eliminates dead branches.
// Untangling eliminates dead algorithmic paths.
//
// Each detection has a corresponding Lean 4 equivalence proof in
// RotationPatterns.lean guaranteeing the untangled form produces
// identical results.
// ═══════════════════════════════════════════════════════════════════════

fn detect_untangling_opportunities(
    topology: &GgTopology,
    diagnostics: &mut Vec<PolyglotDiagnostic>,
) {
    // Build adjacency for nested-loop detection
    let mut node_labels: std::collections::HashMap<&str, &crate::gg_compiler::GgNode> =
        std::collections::HashMap::new();
    for node in &topology.nodes {
        node_labels.insert(&node.id, node);
    }

    for node in &topology.nodes {
        let props = &node.properties;
        let text = props.get("text").map(|s| s.as_str()).unwrap_or("");
        let kind = props.get("kind").map(|s| s.as_str()).unwrap_or("");

        // ── R-SPREAD: Math.max/min(...array) ──
        // Detected when a spread operator applies to an array inside
        // a function call like Math.max or Math.min.
        if text.contains("Math.max(...")
            || text.contains("Math.min(...")
            || text.contains("Math.max( ...")
            || text.contains("Math.min( ...")
        {
            let location = topology
                .source_map
                .find_by_gg_id(&node.id)
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::UntangleSpread,
                message: "Spread into Math.max/min creates argument-list deopt on large arrays. \
                     Untangle: single-pass loop. [THM-FREQ-EQUIVALENCE]"
                    .to_string(),
                severity: DiagnosticSeverity::Hint,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }

        // ── R-SHIFT: .shift() in loop ──
        // Array.shift() is O(N) because it copies all remaining elements.
        // In a while loop, this makes BFS O(N²).
        if (kind == "Loop" || props.get("loop").map(|v| v == "true").unwrap_or(false))
            && text.contains(".shift()")
        {
            let location = topology
                .source_map
                .find_by_gg_id(&node.id)
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::UntangleShift,
                message: ".shift() inside loop body: O(N) per dequeue, O(N²) total. \
                     Untangle: index pointer (let head = 0; queue[head++]). \
                     [THM-QUEUE-SHIFT-EQUIVALENCE]"
                    .to_string(),
                severity: DiagnosticSeverity::Hint,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }

        // ── R-QUADRATIC: nested loop over same collection ──
        // Two nested for-loops where the inner iterates the same
        // collection as the outer suggests an O(N²) pattern.
        if kind == "Loop" {
            // Check if this loop node has a child that is also a Loop
            // over the same data (heuristic: same variable name in text)
            for edge in &topology.edges {
                if !edge.source_ids.contains(&node.id) {
                    continue;
                }
                for target_id in &edge.target_ids {
                    if let Some(target) = node_labels.get(target_id.as_str()) {
                        let target_kind = target
                            .properties
                            .get("kind")
                            .map(|s| s.as_str())
                            .unwrap_or("");
                        if target_kind == "Loop" {
                            // Heuristic: both loops reference same identifier
                            let target_text = target
                                .properties
                                .get("text")
                                .map(|s| s.as_str())
                                .unwrap_or("");
                            // Extract loop variable (crude: look for `for ... of X` or `for ... in X`)
                            let outer_collection = extract_loop_collection(text);
                            let inner_collection = extract_loop_collection(target_text);
                            if !outer_collection.is_empty()
                                && !inner_collection.is_empty()
                                && outer_collection == inner_collection
                            {
                                let location = topology
                                    .source_map
                                    .find_by_gg_id(&node.id)
                                    .map(|entry| entry.span.clone());

                                diagnostics.push(PolyglotDiagnostic {
                                    code: PolyglotDiagnosticCode::UntangleQuadratic,
                                    message: format!(
                                        "Nested loops over '{}': O(N²). \
                                         Untangle: sort-based or hash-based O(N log N). \
                                         [THM-GINI-SORT-EQUIVALENCE]",
                                        outer_collection
                                    ),
                                    severity: DiagnosticSeverity::Hint,
                                    location,
                                    related_nodes: vec![node.id.clone(), target_id.clone()],
                                    theorem_anchor: None,
                                    ghost_mass: None,
                                });
                            }
                        }
                    }
                }
            }
        }

        // ── R-DEFER: division by constant inside loop ──
        // Pattern: `x / N` where N is loop-invariant, inside a Loop node.
        if (kind == "Loop" || props.get("loop").map(|v| v == "true").unwrap_or(false))
            && (text.contains("/ n")
                || text.contains("/ N")
                || text.contains("/ count")
                || text.contains("/ length")
                || text.contains("/ len")
                || text.contains("/ size")
                || text.contains(".length)"))
        {
            // Check if the divisor looks loop-invariant (very crude heuristic)
            let location = topology
                .source_map
                .find_by_gg_id(&node.id)
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::UntangleDefer,
                message: "Division by loop-invariant value inside loop body. \
                         Untangle: accumulate, then divide once at end. \
                         [THM-DEFER-DIVISION-EQUIVALENCE]"
                    .to_string(),
                severity: DiagnosticSeverity::Hint,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }

        // ── R-RECIPROCAL: x /= sum pattern in normalization ──
        if (text.contains("/= sum")
            || text.contains("/ sum")
            || text.contains("/= total")
            || text.contains("/ total")
            || text.contains("/= norm")
            || text.contains("/ norm"))
            && (kind == "Loop" || props.get("loop").map(|v| v == "true").unwrap_or(false))
        {
            let location = topology
                .source_map
                .find_by_gg_id(&node.id)
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::UntangleReciprocal,
                message: "Per-element division in normalization loop. \
                         Untangle: compute 1/sum once, multiply N times. \
                         [THM-RECIPROCAL-MULTIPLY-EQUIV]"
                    .to_string(),
                severity: DiagnosticSeverity::Hint,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

/// Extract the collection name from a loop header (crude heuristic).
/// Handles patterns like `for x of collection`, `for x in collection`,
/// `for (let i = 0; i < collection.length`, etc.
fn extract_loop_collection(text: &str) -> String {
    // Pattern: `of IDENTIFIER` or `in IDENTIFIER`
    for keyword in &[" of ", " in "] {
        if let Some(pos) = text.find(keyword) {
            let after = &text[pos + keyword.len()..];
            let ident: String = after
                .chars()
                .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
                .collect();
            if !ident.is_empty() {
                return ident;
            }
        }
    }
    // Pattern: `i < IDENTIFIER.length`
    if let Some(pos) = text.find(".length") {
        let before = &text[..pos];
        let ident: String = before
            .chars()
            .rev()
            .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
            .collect::<String>()
            .chars()
            .rev()
            .collect();
        if !ident.is_empty() {
            return ident;
        }
    }
    String::new()
}

fn detect_resource_leaks(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    for node in &topology.nodes {
        if node.labels.contains(&"ResourceLeak".to_string()) {
            let resource = node
                .properties
                .get("resource")
                .cloned()
                .unwrap_or_else(|| "unknown".to_string());

            // Find the acquire node this vent connects to.
            let acquire_id = topology
                .edges
                .iter()
                .filter(|e| e.target_ids.contains(&node.id))
                .flat_map(|e| e.source_ids.iter())
                .next()
                .cloned();

            let location = acquire_id
                .as_ref()
                .and_then(|id| topology.source_map.find_by_gg_id(id))
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::ResourceLeak,
                message: format!("{} resource acquired but never released", resource),
                severity: DiagnosticSeverity::Error,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

fn detect_spawn_leaks(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    for node in &topology.nodes {
        if node.labels.contains(&"SpawnLeak".to_string()) {
            let spawn_id = topology
                .edges
                .iter()
                .filter(|e| e.target_ids.contains(&node.id))
                .flat_map(|e| e.source_ids.iter())
                .next()
                .cloned();

            let location = spawn_id
                .as_ref()
                .and_then(|id| topology.source_map.find_by_gg_id(id))
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::SpawnWithoutJoin,
                message: "concurrent task spawned but never joined".to_string(),
                severity: DiagnosticSeverity::Warning,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

fn detect_missing_error_handlers(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    // Find FORK edges with missing_catch property.
    for edge in &topology.edges {
        if edge
            .properties
            .get("missing_catch")
            .map(|v| v == "true")
            .unwrap_or(false)
        {
            let location = edge
                .source_ids
                .first()
                .and_then(|id| topology.source_map.find_by_gg_id(id))
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::MissingErrorHandler,
                message: "try block without catch handler".to_string(),
                severity: DiagnosticSeverity::Warning,
                location,
                related_nodes: edge.source_ids.clone(),
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

fn detect_unbounded_loops(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    let mut seen_sources = std::collections::HashSet::new();
    for edge in &topology.edges {
        if edge
            .properties
            .get("unbounded")
            .map(|v| v == "true")
            .unwrap_or(false)
            && edge
                .properties
                .get("loop")
                .map(|v| v == "true")
                .unwrap_or(false)
        {
            // Deduplicate: only report once per loop source node.
            let source_key = edge.source_ids.first().cloned().unwrap_or_default();
            if !seen_sources.insert(source_key) {
                continue;
            }

            let location = edge
                .source_ids
                .first()
                .and_then(|id| topology.source_map.find_by_gg_id(id))
                .map(|entry| entry.span.clone());

            let code = PolyglotDiagnosticCode::UnboundedLoop;
            let severity = code.severity();
            diagnostics.push(PolyglotDiagnostic {
                code,
                message: "loop without termination proof (unbounded beta-1)".to_string(),
                severity,
                location,
                related_nodes: edge.source_ids.clone(),
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

fn detect_unreachable_components(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    if topology.nodes.is_empty() {
        return;
    }

    // BFS from the first node (entry) to find reachable nodes.
    let mut reachable = std::collections::HashSet::new();
    let mut queue = std::collections::VecDeque::new();

    if let Some(first) = topology.nodes.first() {
        queue.push_back(first.id.clone());
        reachable.insert(first.id.clone());
    }

    while let Some(current) = queue.pop_front() {
        for edge in &topology.edges {
            if edge.source_ids.contains(&current) {
                for target in &edge.target_ids {
                    if reachable.insert(target.clone()) {
                        queue.push_back(target.clone());
                    }
                }
            }
        }
    }

    // Any node not reachable from entry is unreachable.
    for node in &topology.nodes {
        if !reachable.contains(&node.id)
            && !node.labels.contains(&"Vent".to_string())
            && !node.labels.contains(&"ResourceLeak".to_string())
            && !node.labels.contains(&"SpawnLeak".to_string())
        {
            let location = topology
                .source_map
                .find_by_gg_id(&node.id)
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::UnreachableComponent,
                message: format!(
                    "unreachable code: node '{}' not reachable from entry",
                    node.id
                ),
                severity: DiagnosticSeverity::Warning,
                location,
                related_nodes: vec![node.id.clone()],
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

// ═══════════════════════════════════════════════════════════════════════
// Knot Classification: global topology pattern detection
//
// Unlike untangling (per-node patterns), knot classification analyzes
// the GLOBAL structure of the topology graph. These detect:
//   - Hopf links (shared mutable state coupling two components)
//   - Brunnian links (N-ary coupling invisible to (N-1)-ary inspection)
//   - Trefoil knots (triple nested iteration)
//   - Amphichiral knots (mirrored code paths)
//
// The Brunnian detector is the novel one: it finds coupling that is
// invisible to pairwise code review. No existing static analysis tool
// checks for this.
// ═══════════════════════════════════════════════════════════════════════

fn detect_knot_patterns(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    detect_hopf_links(topology, diagnostics);
    detect_brunnian_links(topology, diagnostics);
    detect_trefoil_knots(topology, diagnostics);
    detect_amphichiral_knots(topology, diagnostics);
}

/// Hopf link: two subgraphs connected only through a shared resource node.
/// The shared node has incoming edges from both subgraphs AND outgoing edges
/// to both subgraphs. Neither subgraph is tangled alone.
fn detect_hopf_links(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    // Find nodes that are ENTANGLE targets from multiple sources
    let mut entangle_sources: std::collections::HashMap<&str, Vec<&str>> =
        std::collections::HashMap::new();
    for edge in &topology.edges {
        if edge.edge_type == GgEdgeType::Interfere {
            for target in &edge.target_ids {
                let sources = entangle_sources.entry(target.as_str()).or_default();
                for src in &edge.source_ids {
                    sources.push(src.as_str());
                }
            }
        }
    }

    // A Hopf link exists when a node is entangled from 2+ distinct sources
    for (shared_node, sources) in &entangle_sources {
        if sources.len() >= 2 {
            let location = topology
                .source_map
                .find_by_gg_id(shared_node)
                .map(|entry| entry.span.clone());

            diagnostics.push(PolyglotDiagnostic {
                code: PolyglotDiagnosticCode::HopfLink,
                message: format!(
                    "Hopf link: node '{}' couples {} components through shared state. \
                     Untangle: replace shared mutable state with message passing.",
                    shared_node,
                    sources.len()
                ),
                severity: DiagnosticSeverity::Warning,
                location,
                related_nodes: sources.iter().map(|s| s.to_string()).collect(),
                theorem_anchor: None,
                ghost_mass: None,
            });
        }
    }
}

/// Brunnian link detector: N components where no (N-1) subset is coupled,
/// but all N are collectively entangled through a shared dependency.
///
/// Algorithm:
/// 1. Find all FORK nodes that fan out to 3+ targets
/// 2. For each such FORK, check if removing any one target leaves the
///    remaining targets disconnected from each other (pairwise independent)
/// 3. If yes: the targets form a Brunnian link through the FORK node
///
/// This is O(F * K * (N + E)) where F = fork nodes, K = targets per fork,
/// N = nodes, E = edges. Acceptable for static analysis.
fn detect_brunnian_links(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    // Build adjacency (excluding FORK source edges for component analysis)
    let mut adjacency: std::collections::HashMap<&str, Vec<&str>> =
        std::collections::HashMap::new();
    for edge in &topology.edges {
        for src in &edge.source_ids {
            for tgt in &edge.target_ids {
                adjacency
                    .entry(src.as_str())
                    .or_default()
                    .push(tgt.as_str());
            }
        }
    }

    // Find FORK nodes with 3+ targets
    for edge in &topology.edges {
        if edge.edge_type != GgEdgeType::Fork {
            continue;
        }
        let targets = &edge.target_ids;
        if targets.len() < 3 {
            continue;
        }

        // Check if all targets FOLD back to a common node
        let mut fold_targets: std::collections::HashMap<&str, usize> =
            std::collections::HashMap::new();
        for target in targets {
            // Follow edges from this target to find FOLD destinations
            for fold_edge in &topology.edges {
                if fold_edge.edge_type == GgEdgeType::Fold
                    && fold_edge.source_ids.iter().any(|s| s == target)
                {
                    for ft in &fold_edge.target_ids {
                        *fold_targets.entry(ft.as_str()).or_insert(0) += 1;
                    }
                }
            }
        }

        // Brunnian condition: all targets fold to the SAME node
        // (the shared dependency that creates the collective entanglement)
        for (shared_node, count) in &fold_targets {
            if *count >= targets.len() {
                // All targets fold to this node.
                // Check pairwise independence: removing any one target,
                // do the others still connect through the shared node?
                // For Brunnian: YES (removing one unlinks all).
                // We approximate: if the shared node is also the FORK source
                // (creates a cycle through all targets), it's Brunnian.
                let fork_source = edge.source_ids.first().map(|s| s.as_str());
                let is_cycle = fork_source == Some(*shared_node);

                if is_cycle {
                    let location = topology
                        .source_map
                        .find_by_gg_id(shared_node)
                        .map(|entry| entry.span.clone());

                    diagnostics.push(PolyglotDiagnostic {
                        code: PolyglotDiagnosticCode::BrunnianLink,
                        message: format!(
                            "Brunnian link: {} components collectively entangled through '{}'. \
                             No pair is directly coupled, but all {} are linked through the shared \
                             dependency. INVISIBLE to pairwise code review. \
                             Untangle: make per-pair dependencies explicit.",
                            targets.len(),
                            shared_node,
                            targets.len()
                        ),
                        severity: DiagnosticSeverity::Warning,
                        location,
                        related_nodes: targets.clone(),
                        theorem_anchor: None,
                        ghost_mass: None,
                    });
                }
            }
        }
    }
}

/// Trefoil knot: three nested loops over the same collection.
/// Detected as a chain of 3 Loop nodes where all reference the same identifier.
fn detect_trefoil_knots(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    // Build node lookup
    let node_map: std::collections::HashMap<&str, &GgNode> =
        topology.nodes.iter().map(|n| (n.id.as_str(), n)).collect();

    // Build adjacency
    let mut children: std::collections::HashMap<&str, Vec<&str>> = std::collections::HashMap::new();
    for edge in &topology.edges {
        for src in &edge.source_ids {
            for tgt in &edge.target_ids {
                children.entry(src.as_str()).or_default().push(tgt.as_str());
            }
        }
    }

    // Find chains of 3 Loop nodes
    for node in &topology.nodes {
        let kind = node
            .properties
            .get("kind")
            .map(std::string::String::as_str)
            .unwrap_or("");
        if kind != "Loop" {
            continue;
        }
        let collection_a = extract_loop_collection(
            node.properties
                .get("text")
                .map(std::string::String::as_str)
                .unwrap_or(""),
        );
        if collection_a.is_empty() {
            continue;
        }

        // Check children for second loop over same collection
        for child_id in children.get(node.id.as_str()).unwrap_or(&vec![]) {
            let child = match node_map.get(child_id) {
                Some(n) => n,
                None => continue,
            };
            let child_kind = child
                .properties
                .get("kind")
                .map(std::string::String::as_str)
                .unwrap_or("");
            if child_kind != "Loop" {
                continue;
            }
            let collection_b = extract_loop_collection(
                child
                    .properties
                    .get("text")
                    .map(std::string::String::as_str)
                    .unwrap_or(""),
            );
            if collection_b != collection_a {
                continue;
            }

            // Check grandchildren for third loop
            for grandchild_id in children.get(*child_id).unwrap_or(&vec![]) {
                let grandchild = match node_map.get(grandchild_id) {
                    Some(n) => n,
                    None => continue,
                };
                let gc_kind = grandchild
                    .properties
                    .get("kind")
                    .map(std::string::String::as_str)
                    .unwrap_or("");
                if gc_kind != "Loop" {
                    continue;
                }
                let collection_c = extract_loop_collection(
                    grandchild
                        .properties
                        .get("text")
                        .map(std::string::String::as_str)
                        .unwrap_or(""),
                );
                if collection_c != collection_a {
                    continue;
                }

                // Triple nested loop over same collection = trefoil
                let location = topology
                    .source_map
                    .find_by_gg_id(&node.id)
                    .map(|entry| entry.span.clone());

                diagnostics.push(PolyglotDiagnostic {
                    code: PolyglotDiagnosticCode::TrefoilKnot,
                    message: format!(
                        "Trefoil knot: triple nested loop over '{}' (3 crossings, O(N³)). \
                         Untangle: sort + single pass (O(N log N)). [THM-GINI-SORT-EQUIVALENCE]",
                        collection_a
                    ),
                    severity: DiagnosticSeverity::Hint,
                    location,
                    related_nodes: vec![
                        node.id.clone(),
                        child_id.to_string(),
                        grandchild_id.to_string(),
                    ],
                    theorem_anchor: None,
                    ghost_mass: None,
                });

                break; // One trefoil per outer loop is enough
            }
        }
    }
}

/// Amphichiral knot: two code paths that mirror each other.
/// Detected when a FORK has exactly 2 targets whose handler labels
/// are semantic inverses (build/query, encode/decode, serialize/deserialize, etc.).
fn detect_amphichiral_knots(topology: &GgTopology, diagnostics: &mut Vec<PolyglotDiagnostic>) {
    let mirror_pairs: &[(&str, &str)] = &[
        ("serialize", "deserialize"),
        ("encode", "decode"),
        ("encrypt", "decrypt"),
        ("compress", "decompress"),
        ("marshal", "unmarshal"),
        ("pack", "unpack"),
        ("build", "query"),
        ("write", "read"),
        ("push", "pull"),
        ("send", "receive"),
        ("upload", "download"),
        ("insert", "select"),
        ("create", "delete"),
    ];

    let node_map: std::collections::HashMap<&str, &GgNode> =
        topology.nodes.iter().map(|n| (n.id.as_str(), n)).collect();

    for edge in &topology.edges {
        if edge.edge_type != GgEdgeType::Fork || edge.target_ids.len() != 2 {
            continue;
        }

        let target_a = match node_map.get(edge.target_ids[0].as_str()) {
            Some(n) => n,
            None => continue,
        };
        let target_b = match node_map.get(edge.target_ids[1].as_str()) {
            Some(n) => n,
            None => continue,
        };

        let text_a = target_a
            .properties
            .get("text")
            .or_else(|| target_a.labels.first())
            .map(|s: &String| s.to_lowercase())
            .unwrap_or_default();
        let text_b = target_b
            .properties
            .get("text")
            .or_else(|| target_b.labels.first())
            .map(|s: &String| s.to_lowercase())
            .unwrap_or_default();

        for (fwd, rev) in mirror_pairs {
            if (text_a.contains(fwd) && text_b.contains(rev))
                || (text_a.contains(rev) && text_b.contains(fwd))
            {
                let location = edge
                    .source_ids
                    .first()
                    .and_then(|id| topology.source_map.find_by_gg_id(id))
                    .map(|entry| entry.span.clone());

                diagnostics.push(PolyglotDiagnostic {
                    code: PolyglotDiagnosticCode::AmphichiralKnot,
                    message: format!(
                        "Amphichiral knot: '{}/{}' are mirror paths. \
                         Untangling one automatically untangles the other. \
                         Fix the canonical direction; the inverse follows.",
                        fwd, rev
                    ),
                    severity: DiagnosticSeverity::Hint,
                    location,
                    related_nodes: edge.target_ids.clone(),
                    theorem_anchor: None,
                    ghost_mass: None,
                });

                break;
            }
        }
    }
}

/// Filter out diagnostics suppressed by `polyglot:ignore` comments in source.
///
/// Checks the diagnostic's source line and the line above it for:
/// - `polyglot:ignore` (suppresses all diagnostics on that line)
/// - `polyglot:ignore RULE_NAME` (suppresses only that specific rule)
pub fn filter_suppressed(
    diagnostics: Vec<PolyglotDiagnostic>,
    sources: &std::collections::HashMap<String, String>,
) -> Vec<PolyglotDiagnostic> {
    diagnostics
        .into_iter()
        .filter(|diag| {
            let Some(ref loc) = diag.location else {
                return true;
            };
            let Some(source) = sources.get(&loc.file) else {
                return true;
            };

            let lines: Vec<&str> = source.lines().collect();
            let line_idx = loc.start_line.saturating_sub(1);

            // Check the flagged line and up to 3 lines above (comments may precede by 1-3 lines).
            let mut check_lines = vec![line_idx];
            for offset in 1..=3 {
                if line_idx >= offset {
                    check_lines.push(line_idx - offset);
                }
            }

            for idx in check_lines {
                if let Some(line) = lines.get(idx) {
                    if let Some(pos) = line.find("polyglot:ignore") {
                        let after = &line[pos + 15..].trim_start();
                        // Bare `polyglot:ignore` suppresses everything.
                        if after.is_empty()
                            || after.starts_with("--")
                            || after.starts_with("//")
                            || after.starts_with('#')
                        {
                            return false;
                        }
                        // `polyglot:ignore RULE_NAME` suppresses that specific rule.
                        if after.starts_with(diag.code.as_str()) {
                            return false;
                        }
                    }
                }
            }

            true
        })
        .collect()
}

/// Generate SARIF 2.1.0 output from polyglot diagnostics.
pub fn diagnostics_to_sarif(
    file_path: &str,
    language: &str,
    diagnostics: &[PolyglotDiagnostic],
) -> serde_json::Value {
    let mut rules = Vec::new();
    let mut rule_ids_seen = std::collections::HashSet::new();
    let mut results = Vec::new();

    for diag in diagnostics {
        let rule_id = format!("gnosis.polyglot.{}", diag.code.as_str());

        if rule_ids_seen.insert(rule_id.clone()) {
            rules.push(serde_json::json!({
                "id": rule_id,
                "shortDescription": { "text": diag.code.as_str() },
                "fullDescription": { "text": diag.code.description() },
            }));
        }

        let mut result = serde_json::json!({
            "ruleId": rule_id,
            "level": diag.severity.as_sarif(),
            "message": { "text": diag.message },
        });

        if diag.theorem_anchor.is_some() || diag.ghost_mass.is_some() {
            result["properties"] = serde_json::json!({});
            if let Some(ref theorem_anchor) = diag.theorem_anchor {
                result["properties"]["theoremAnchor"] = serde_json::json!(theorem_anchor);
            }
            if let Some(ghost_mass) = diag.ghost_mass {
                result["properties"]["ghostMass"] = serde_json::json!(ghost_mass);
            }
        }

        if let Some(ref loc) = diag.location {
            result["locations"] = serde_json::json!([{
                "physicalLocation": {
                    "artifactLocation": { "uri": loc.file },
                    "region": {
                        "startLine": loc.start_line,
                        "startColumn": loc.start_column,
                        "endLine": loc.end_line,
                        "endColumn": loc.end_column,
                    }
                }
            }]);
        } else {
            result["locations"] = serde_json::json!([{
                "physicalLocation": {
                    "artifactLocation": { "uri": file_path }
                }
            }]);
        }

        results.push(result);
    }

    if results.is_empty() {
        results.push(serde_json::json!({
            "ruleId": "gnosis.polyglot.pass",
            "level": "note",
            "message": { "text": format!("Polyglot analysis passed for {} ({})", file_path, language) },
            "locations": [{
                "physicalLocation": {
                    "artifactLocation": { "uri": file_path }
                }
            }]
        }));
    }

    serde_json::json!({
        "version": "2.1.0",
        "$schema": "https://json.schemastore.org/sarif-2.1.0.json",
        "runs": [{
            "tool": {
                "driver": {
                    "name": "gnosis-polyglot",
                    "informationUri": "https://github.com/forkjoin-ai/gnosis",
                    "version": env!("CARGO_PKG_VERSION"),
                    "rules": rules,
                }
            },
            "results": results,
        }]
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::parse_and_extract;

    #[test]
    fn detects_resource_leak_diagnostic() {
        let source = r#"
def leaky():
    f = open("data.txt", "r")
    data = f.read()
    return data
"#;
        let result = parse_and_extract(source, "test.py").unwrap();
        let topo = &result.topologies[0].topology;
        let diags = analyze_topology(topo);

        let has_leak = diags
            .iter()
            .any(|d| d.code == PolyglotDiagnosticCode::ResourceLeak);
        assert!(has_leak, "should detect resource leak");
    }

    #[test]
    fn detects_spawn_leak_diagnostic() {
        let source = r#"
package main

func leaky() {
    go worker()
}
"#;
        let result = parse_and_extract(source, "test.go").unwrap();
        let topo = &result.topologies[0].topology;
        let diags = analyze_topology(topo);

        let has_spawn_leak = diags
            .iter()
            .any(|d| d.code == PolyglotDiagnosticCode::SpawnWithoutJoin);
        assert!(has_spawn_leak, "should detect spawn without join");
    }

    #[test]
    fn sarif_output_is_valid() {
        let diags = vec![PolyglotDiagnostic {
            code: PolyglotDiagnosticCode::ResourceLeak,
            message: "file handle leaked".to_string(),
            severity: DiagnosticSeverity::Error,
            location: Some(SourceSpan {
                file: "test.py".to_string(),
                start_line: 3,
                start_column: 5,
                end_line: 3,
                end_column: 30,
                start_byte: 20,
                end_byte: 45,
            }),
            related_nodes: vec!["acquire_1".to_string()],
            theorem_anchor: Some("resource_leak_is_cavitation".to_string()),
            ghost_mass: Some(1),
        }];

        let sarif = diagnostics_to_sarif("test.py", "python", &diags);

        assert_eq!(sarif["version"], "2.1.0");
        assert!(sarif["runs"][0]["results"].as_array().unwrap().len() > 0);
        assert_eq!(
            sarif["runs"][0]["results"][0]["ruleId"],
            "gnosis.polyglot.RESOURCE_LEAK"
        );
        assert_eq!(sarif["runs"][0]["results"][0]["level"], "error");
        assert_eq!(
            sarif["runs"][0]["results"][0]["locations"][0]["physicalLocation"]["region"]
                ["startLine"],
            3
        );
        assert_eq!(
            sarif["runs"][0]["results"][0]["properties"]["theoremAnchor"],
            "resource_leak_is_cavitation"
        );
        assert_eq!(sarif["runs"][0]["results"][0]["properties"]["ghostMass"], 1);
    }

    #[test]
    fn ghost_mass_ledger_tracks_unreleased_forked_mass() {
        let source = r#"
function leaky() {
    const stream = fs.createReadStream("demo.txt");
    return stream;
}
"#;
        let result = parse_and_extract(source, "test.ts").unwrap();
        let topo = &result.topologies[0].topology;
        let ledger = compute_ghost_mass_ledger(topo);

        assert_eq!(ledger.forked_mass, 1);
        assert_eq!(ledger.folded_mass, 0);
        assert_eq!(ledger.vented_mass, 1);
        assert_eq!(ledger.ghost_mass, 1);
        assert_eq!(ledger.leak_debt, 1);
    }

    #[test]
    fn sarif_pass_when_no_diagnostics() {
        let sarif = diagnostics_to_sarif("clean.py", "python", &[]);
        let results = sarif["runs"][0]["results"].as_array().unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0]["level"], "note");
    }
}
